import React, { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import {
  Package,
  Plus,
  Search,
  Edit,
  CheckCircle,
  Truck,
  XCircle,
  AlertCircle,
  RefreshCw,
  Trash2,
  Mail,
  BarChart3,
  Shield,
  ClipboardList,
  MapPin,
  FileText,
  Hourglass,
  Home,
  LogOut,
  Users,
} from 'lucide-react';
import './AdminDashboard.css';
import { useAuth } from '../context/AuthContext';
import {
  fetchAllParcels,
  fetchAdminStats,
  fetchComplaints,
  createParcel,
  updateParcelStatus,
  updateParcel,
  deleteParcel,
  mapServerParcel,
  updateComplaintStatus,
  fetchAllAgents,
  createAgent,
  updateAgent,
  deleteAgent,
  toggleAgentStatus,
} from '../services/api';
import { STATUS_OPTIONS, getStatusBadge, getStatusIcon } from '../utils/statusHelpers';
import { calculatePrice, getServiceMeta } from '../utils/priceCalculator';

const emptyForm = {
  senderName: '',
  senderEmail: '',
  senderPhone: '',
  receiverName: '',
  receiverPhone: '',
  sourceCity: '',
  sourcePincode: '',
  destinationCity: '',
  destinationPincode: '',
  serviceType: 'Speed Post',
  packageType: 'Document',
  pickupMode: 'Pickup',
  pickupDate: '',
  pickupSlot: '',
  weightKg: '',
  paymentMethod: 'Cash',
  codAmount: '',
  insurance: false,
  otpDelivery: false,
  notes: '',
  assignedAgent: '',
  postOfficeCenter: '',
};

export default function AdminDashboard() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const [parcels, setParcels] = useState([]);
  const [complaints, setComplaints] = useState([]);
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [serviceFilter, setServiceFilter] = useState('all');
  const [dateRange, setDateRange] = useState({ from: '', to: '' });
  const [activeSection, setActiveSection] = useState('overview');

  const [showParcelForm, setShowParcelForm] = useState(false);
  const [editingParcel, setEditingParcel] = useState(null);
  const [formData, setFormData] = useState(emptyForm);
  const [centers, setCenters] = useState([
    { name: 'Head Office', code: 'HO-01', address: 'Connaught Place, New Delhi', contact: '+91-9999999999', serviceArea: 'NCR' },
  ]);
  const [centerForm, setCenterForm] = useState({ name: '', code: '', address: '', contact: '', serviceArea: '' });

  const [statusModal, setStatusModal] = useState(null);
  const [reportFilters, setReportFilters] = useState({ status: 'all', service: 'all', location: '', from: '', to: '' });
  const [pendingDelete, setPendingDelete] = useState(null);

  // Agent management state
  const [agents, setAgents] = useState([]);
  const [showAgentForm, setShowAgentForm] = useState(false);
  const [editingAgent, setEditingAgent] = useState(null);
  const [agentForm, setAgentForm] = useState({
    fullName: '',
    mobile: '',
    email: '',
    agentId: '',
    password: '',
    assignedCity: '',
    assignedArea: '',
    postOffice: '',
    hub: '',
    vehicleType: 'Bike',
    licenseNumber: '',
    shiftTime: 'Full Day',
    status: 'Active',
  });

  useEffect(() => {
    if (!user || user.role !== 'admin') {
      navigate('/admin/login');
      return;
    }
    loadDashboard();
  }, [user, navigate]);

  const loadDashboard = async () => {
    setLoading(true);
    try {
      const [parcelRes, statsRes, complaintsRes, agentsRes] = await Promise.allSettled([
        fetchAllParcels(),
        fetchAdminStats(),
        fetchComplaints(),
        fetchAllAgents(),
      ]);

      if (parcelRes.status === 'fulfilled') {
        setParcels(parcelRes.value.map(mapServerParcel));
      }
      if (statsRes.status === 'fulfilled') {
        setStats(statsRes.value?.totals || null);
      }
      if (complaintsRes.status === 'fulfilled') {
        setComplaints(complaintsRes.value);
      }
      if (agentsRes.status === 'fulfilled') {
        setAgents(agentsRes.value);
      }
    } catch (error) {
      console.error('Dashboard load failed', error);
      alert('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setFormData((prev) => ({ 
      ...prev, 
      [name]: type === 'checkbox' ? checked : value 
    }));
  };

  const handleCenterChange = (e) => {
    const { name, value } = e.target;
    setCenterForm((prev) => ({ ...prev, [name]: value }));
  };

  const addCenter = () => {
    if (!centerForm.name || !centerForm.code) {
      alert('Center name and code are required');
      return;
    }
    setCenters((prev) => [...prev, centerForm]);
    setCenterForm({ name: '', code: '', address: '', contact: '', serviceArea: '' });
  };

  const removeCenter = (code) => {
    setCenters((prev) => prev.filter((c) => c.code !== code));
  };

  const openCreateForm = () => {
    setEditingParcel(null);
    setFormData(emptyForm);
    setShowParcelForm(true);
  };

  const openEditForm = (parcel) => {
    setEditingParcel(parcel);
    setFormData({
      senderName: parcel.senderName || '',
      senderEmail: parcel.senderEmail || '',
      senderPhone: parcel.senderPhone || '',
      receiverName: parcel.receiverName || '',
      receiverPhone: parcel.receiverPhone || '',
      sourceCity: parcel.sourceCity || '',
      sourcePincode: parcel.sourcePincode || '',
      destinationCity: parcel.destinationCity || '',
      destinationPincode: parcel.destinationPincode || '',
      serviceType: parcel.serviceType || 'Speed Post',
      packageType: parcel.packageType || 'Document',
      pickupMode: parcel.pickupMode || 'Pickup',
      pickupDate: parcel.pickupDate ? parcel.pickupDate.substring(0, 10) : '',
      pickupSlot: parcel.pickupSlot || '',
      weightKg: parcel.weightKg || '',
      paymentMethod: parcel.paymentMethod || 'Cash',
      codAmount: parcel.codAmount || '',
      insurance: parcel.insurance || false,
      otpDelivery: parcel.otpDelivery || false,
      notes: parcel.notes || '',
      assignedAgent: parcel.assignedAgent || '',
      postOfficeCenter: parcel.postOfficeCenter || '',
    });
    setShowParcelForm(true);
  };

  const handleSaveParcel = async (e) => {
    e?.preventDefault();
    setSaving(true);
    try {
      // Calculate price automatically
      const calculatedPrice = calculatePrice(formData);
      if (!calculatedPrice) {
        alert('Please enter weight to calculate price');
        setSaving(false);
        return;
      }

      const payload = {
        ...formData,
        weightKg: Number(formData.weightKg),
        costInr: calculatedPrice,
        codAmount: formData.codAmount ? Number(formData.codAmount) : undefined,
      };
      if (editingParcel) {
        await updateParcel(editingParcel.id, payload);
        alert('Shipment updated successfully');
      } else {
        const res = await createParcel(payload);
        alert(
          `Shipment booked successfully!\nRequest ID: ${res.parcel?.requestId || 'N/A'}\nTracking ID: ${
            res.trackingId
          }\n\nTracking ID has been sent to customer email if provided.`
        );
      }
      setShowParcelForm(false);
      setEditingParcel(null);
      setFormData(emptyForm);
      loadDashboard();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to save shipment');
    } finally {
      setSaving(false);
    }
  };

  const handleStatusUpdate = async (parcelId, status) => {
    setSaving(true);
    try {
      await updateParcelStatus(parcelId, status);
      alert('Status updated and tracking/email handled automatically.');
      setStatusModal(null);
      loadDashboard();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to update status');
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteParcel = async () => {
    if (!pendingDelete) return;
    setSaving(true);
    try {
      await deleteParcel(pendingDelete.id);
      setPendingDelete(null);
      loadDashboard();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to delete shipment');
    } finally {
      setSaving(false);
    }
  };

  const handleComplaintStatus = async (complaint) => {
    const nextStatus = complaint.status === 'resolved' ? 'in_progress' : 'resolved';
    try {
      await updateComplaintStatus(complaint._id, { status: nextStatus });
      loadDashboard();
    } catch (error) {
      alert('Failed to update complaint');
    }
  };

  // Agent management functions
  const openAgentForm = () => {
    setEditingAgent(null);
    setAgentForm({
      fullName: '',
      mobile: '',
      email: '',
      agentId: '',
      password: '',
      assignedCity: '',
      assignedArea: '',
      postOffice: '',
      hub: '',
      vehicleType: 'Bike',
      licenseNumber: '',
      shiftTime: 'Full Day',
      status: 'Active',
    });
    setShowAgentForm(true);
  };

  const openEditAgentForm = (agent) => {
    setEditingAgent(agent);
    setAgentForm({
      fullName: agent.fullName || '',
      mobile: agent.mobile || '',
      email: agent.email || '',
      agentId: agent.agentId || '',
      password: '',
      assignedCity: agent.assignedCity || '',
      assignedArea: agent.assignedArea || '',
      postOffice: agent.postOffice || '',
      hub: agent.hub || '',
      vehicleType: agent.vehicleType || 'Bike',
      licenseNumber: agent.licenseNumber || '',
      shiftTime: agent.shiftTime || 'Full Day',
      status: agent.status || 'Active',
    });
    setShowAgentForm(true);
  };

  const handleAgentInputChange = (e) => {
    const { name, value } = e.target;
    setAgentForm((prev) => ({ ...prev, [name]: value }));
