  const handleSaveAgent = async (e) => {
    e?.preventDefault();
    setSaving(true);
    try {
      const payload = { ...agentForm };
      // Remove empty password
      if (!payload.password) {
        delete payload.password;
      }

      if (editingAgent) {
        await updateAgent(editingAgent._id, payload);
        alert('Agent updated successfully');
      } else {
        const res = await createAgent(payload);
        alert(
          `Agent created successfully!\nAgent ID: ${res.agent.agentId}\nPassword: ${res.credentials.password}\n\nPlease share these credentials with the agent.`
        );
      }
      setShowAgentForm(false);
      setEditingAgent(null);
      loadDashboard();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to save agent');
    } finally {
      setSaving(false);
    }
  };

  const handleDeleteAgent = async (agentId) => {
    if (!window.confirm('Are you sure you want to delete this agent?')) {
      return;
    }
    setSaving(true);
    try {
      await deleteAgent(agentId);
      alert('Agent deleted successfully');
      loadDashboard();
    } catch (error) {
      alert(error.response?.data?.message || 'Failed to delete agent');
    } finally {
      setSaving(false);
    }
  };

  const handleToggleAgentStatus = async (agentId) => {
    setSaving(true);
    try {
      await toggleAgentStatus(agentId);
      loadDashboard();
